import { db } from '../database';

const router = Router();

/** Validate post input — returns error message or null if valid */
function validatePost(body: any): string | null {
  if (!body.title || typeof body.title !== 'string') return 'title is required';
  if (body.title.length < 3 || body.title.length > 200) return 'title must be 3-200 characters';
  if (!body.content || typeof body.content !== 'string') return 'content is required';
  if (body.content.length < 10) return 'content must be at least 10 characters';
  return null;
}

// List posts
router.get('/', async (req: Request, res: Response) => {
  const limit = Math.min(Number(req.query.limit) || 20, 100);
  const offset = Number(req.query.offset) || 0;
  const { rows } = await db.query(
    'SELECT id, title, created_at, user_id FROM posts ORDER BY created_at DESC LIMIT $1 OFFSET $2',
    [limit, offset]
  );
  res.json(rows);
});

// Get single post
router.get('/:id', async (req: Request, res: Response) => {
  const { rows } = await db.query('SELECT * FROM posts WHERE id = $1', [req.params.id]);
  if (rows.length === 0) return res.status(404).json({ error: 'Post not found' });
  res.json(rows[0]);
});

// Create post
router.post('/', async (req: Request, res: Response) => {
  const error = validatePost(req.body);
  if (error) return res.status(400).json({ error });

  const { title, content } = req.body;
  const { rows } = await db.query(
    'INSERT INTO posts (title, content, user_id) VALUES ($1, $2, $3) RETURNING *',
    [title, content, req.userId]
  );
  res.status(201).json(rows[0]);
});

// Update post
router.put('/:id', async (req: Request, res: Response) => {
  const { rows: existing } = await db.query('SELECT user_id FROM posts WHERE id = $1', [req.params.id]);
  if (existing.length === 0) return res.status(404).json({ error: 'Post not found' });
  if (existing[0].user_id !== req.userId) return res.status(403).json({ error: 'Not your post' });

  const error = validatePost(req.body);
  if (error) return res.status(400).json({ error });

  const { title, content } = req.body;
  const { rows } = await db.query(
    'UPDATE posts SET title = $1, content = $2, updated_at = NOW() WHERE id = $3 RETURNING *',
    [title, content, req.params.id]
  );
  res.json(rows[0]);
});

// Delete post
router.delete('/:id', async (req: Request, res: Response) => {
  const { rows } = await db.query('SELECT user_id FROM posts WHERE id = $1', [req.params.id]);
  if (rows.length === 0) return res.status(404).json({ error: 'Post not found' });
  if (rows[0].user_id !== req.userId) return res.status(403).json({ error: 'Not your post' });

  await db.query('DELETE FROM posts WHERE id = $1', [req.params.id]);
  res.status(204).send();
});

export default router;
"}}
