{"content": "import { Pool } from 'pg';
import { User } from './types';

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

export function getUser(id: string, callback: (err: Error | null, user?: User) => void) {
  pool.query('SELECT * FROM users WHERE id = $1', [id], (err, result) => {
    if (err) return callback(err);
    if (result.rows.length === 0) return callback(null, undefined);
    callback(null, result.rows[0]);
  });
}

export function saveUser(user: User, callback: (err: Error | null) => void) {
  pool.query(
    'INSERT INTO users (id, username, email) VALUES ($1, $2, $3) ON CONFLICT (id) DO UPDATE SET username = $2, email = $3',
    [user.id, user.username, user.email],
    (err) => callback(err)
  );
}

export function deleteUser(id: string, callback: (err: Error | null) => void) {
  pool.query('DELETE FROM users WHERE id = $1', [id], (err) => callback(err));
}
"}

All three use the `pg` pool's callback API, but `pg` supports promises natively. Straightforward conversion.

