```tool_call
{"name": "write_file", "arguments": {"path": "src/env.ts", "content": "/**
 * Environment variable validation.
 * Import this at the top of your entry point — the app will
 * crash immediately with a clear message if anything is missing.
 */

interface EnvVar {
  name: string;
  required: boolean;
  default?: string;
}

const ENV_SCHEMA: EnvVar[] = [
  { name: 'DATABASE_URL', required: true },
  { name: 'JWT_SECRET', required: true },
  { name: 'SMTP_HOST', required: false, default: '' },
  { name: 'PORT', required: false, default: '3000' },
];

const missing: string[] = [];

for (const v of ENV_SCHEMA) {
  if (!process.env[v.name]) {
    if (v.required) {
      missing.push(v.name);
    } else if (v.default !== undefined) {
      process.env[v.name] = v.default;
    }
  }
}

if (missing.length > 0) {
  console.error('\n  Missing required environment variables:\n');
  for (const name of missing) {
    console.error(`    - ${name}`);
  }
  console.error('\n  Set them in .env or your environment.\n');
  process.exit(1);
}

// Type-safe env access after validation
export const env = {
  DATABASE_URL: process.env.DATABASE_URL!,
  JWT_SECRET: process.env.JWT_SECRET!,
  SMTP_HOST: process.env.SMTP_HOST || '',
  PORT: Number(process.env.PORT || 3000),
} as const;
"}}
