```tool_call
{"name": "write_file", "arguments": {"path": "src/middleware/requestLogger.ts", "content": "import { Request, Response, NextFunction } from 'express';

export function requestLogger(req: Request, res: Response, next: NextFunction) {
  const start = Date.now();

  // Capture the original end method to intercept the response
  const originalEnd = res.end;
  res.end = function (...args: any[]) {
    const duration = Date.now() - start;
    const log = {
      timestamp: new Date().toISOString(),
      method: req.method,
      path: req.originalUrl,
      status: res.statusCode,
      duration_ms: duration,
    };

    // Use JSON for structured logging
    process.stdout.write(JSON.stringify(log) + '\n');

    return originalEnd.apply(res, args);
  } as any;

  next();
}
"}}
