export async function fetchWithCancel(url: string, timeoutMs = 5000) {
  const source = axios.CancelToken.source();
  const timer = setTimeout(() => source.cancel('timeout'), timeoutMs);

  try {
    const res = await axios.get(url, { cancelToken: source.token });
    clearTimeout(timer);
    return res.data;
  } catch (err) {
    if (axios.isCancel(err)) throw new Error('Request timed out');
