```tool_call
{"name": "write_file", "arguments": {"path": "scripts/migrate-users.ts", "content": "import { readFileSync } from 'fs';
import { Pool } from 'pg';
import { randomUUID } from 'crypto';

const db = new Pool({ connectionString: process.env.DATABASE_URL });

interface OldUser {
  id: string;
  name: string;
  email_address: string;
  hashed_pw: string;
  joined: string;
  roles: string;
  prefs: string;
}

async function migrate() {
  const raw = readFileSync('data/users_export.json', 'utf-8');
  const oldUsers: OldUser[] = JSON.parse(raw);

  console.log(`Migrating ${oldUsers.length} users...`);
  let success = 0;
  let failed = 0;

  for (const user of oldUsers) {
    const client = await db.connect();
    try {
      await client.query('BEGIN');

      // Parse fields
      const [firstName, ...lastParts] = user.name.split(' ');
      const username = `${firstName.toLowerCase()}${lastParts[0]?.[0]?.toLowerCase() || ''}`;
      const prefs = JSON.parse(user.prefs || '{}');
      const roles = user.roles.split(',').map(r => r.trim()).filter(Boolean);
      const createdAt = new Date(user.joined).toISOString();
      const newId = randomUUID();

      await client.query(
        `INSERT INTO users (id, username, email, password_hash, created_at, preferences)
         VALUES ($1, $2, $3, $4, $5, $6)`,
        [newId, username, user.email_address, user.hashed_pw, createdAt, JSON.stringify(prefs)]
      );

      for (const role of roles) {
        await client.query(
          `INSERT INTO user_roles (user_id, role) VALUES ($1, $2)`,
          [newId, role]
        );
      }

      await client.query('COMMIT');
      success++;
      console.log(`  OK: ${user.email_address} (${roles.join(', ')})`);
    } catch (err) {
      await client.query('ROLLBACK');
      failed++;
      console.error(`  FAIL: ${user.email_address}:`, (err as Error).message);
    } finally {
      client.release();
    }
  }

  console.log(`\nDone: ${success} migrated, ${failed} failed`);
  await db.end();
}

migrate().catch(console.error);
"}}
