Two instantiations — that means two intervals and two growing Maps. Fixing all three issues.

```tool_call
{"name": "write_file", "arguments": {"path": "src/services/MetricsService.ts", "content": "export class MetricsService {
  private data: Map<string, number> = new Map(); // counts, not unbounded arrays
  private interval: NodeJS.Timeout;

  constructor() {
    this.interval = setInterval(() => this.flush(), 5000);
    // Allow process to exit even if interval is active
    this.interval.unref();
  }

  track(req: { path: string }) {
    const key = req.path;
    this.data.set(key, (this.data.get(key) || 0) + 1);
  }

  flush() {
    if (this.data.size > 0) {
      console.log('Metrics:', Object.fromEntries(this.data));
      this.data.clear(); // prevent unbounded growth
    }
  }

  destroy() {
    clearInterval(this.interval);
    this.data.clear();
  }
}

// Singleton — one instance across the app
export const metrics = new MetricsService();
"}}
