const stripe = new Stripe(process.env.STRIPE_KEY!);

export async function processPayment(userId: string, amount: number, currency: string) {
  const log = logger.child({ userId, amount, currency, operation: 'processPayment' });
  log.info('Payment attempt started');

  try {
    const intent = await stripe.paymentIntents.create({
      amount,
      currency,
      metadata: { userId },
    });

    log.info({
      intentId: intent.id,
      status: intent.status,
    }, 'Payment intent created');

    return intent;
  } catch (err) {
    log.error({
      err,
      stripeCode: (err as Stripe.errors.StripeError)?.code,
    }, 'Payment processing failed');
    throw err;
  }
}

export async function refundPayment(intentId: string, reason?: string) {
  const log = logger.child({ intentId, reason, operation: 'refundPayment' });
  log.info('Refund attempt started');

  try {
    const refund = await stripe.refunds.create({
      payment_intent: intentId,
      reason: reason as Stripe.RefundCreateParams.Reason,
    });

    log.info({
      refundId: refund.id,
      status: refund.status,
      amount: refund.amount,
    }, 'Refund created');

    return refund;
  } catch (err) {
    log.error({ err }, 'Refund failed');
    throw err;
  }
}
