         ON CONFLICT (user_id) DO UPDATE SET score = EXCLUDED.score, recorded_at = EXCLUDED.recorded_at`,
        [row.id, row.name, row.email, parseFloat(row.score), row.created_at]
      );
      inserted++;
    } catch (err) {
      console.error(`  Row ${row.id} failed:`, (err as Error).message);
      skipped++;
    }
  }

  console.log(`  Done: ${inserted} inserted/updated, ${skipped} failed`);

  // Move file to processed directory
  const dest = join(DONE_DIR, basename(filePath));
  renameSync(filePath, dest);
  console.log(`  Moved to ${dest}`);
}

const watcher = chokidar.watch(`${WATCH_DIR}/*.csv`, {
  persistent: true,
  awaitWriteFinish: { stabilityThreshold: 1000 }, // wait 1s after last write
});

watcher
  .on('add', (path) => importFile(path).catch(console.error))
  .on('error', console.error);

console.log(`Watching ${WATCH_DIR} for CSV files...`);
"}}
