{"content": "import { db } from '../database';

export async function getPosts(limit: number, offset: number) {
  const { rows } = await db.query('SELECT * FROM posts LIMIT $1 OFFSET $2', [limit, offset]);
  const enriched = await Promise.all(
    rows.map(async (post) => {
      const { rows: authorRows } = await db.query('SELECT * FROM users WHERE id = $1', [post.author_id]);
      return { ...post, author: authorRows[0] };
    })
  );
  return enriched;
}
"}

