export async function getPosts(limit: number, offset: number) {
  // Single JOIN query instead of N+1 individual user lookups
  const { rows } = await db.query(`
    SELECT
      p.*,
      json_build_object('id', u.id, 'username', u.username, 'avatar_url', u.avatar_url) AS author
    FROM posts p
    JOIN users u ON p.author_id = u.id
    ORDER BY p.created_at DESC
    LIMIT $1 OFFSET $2
  `, [limit, offset]);
  return rows;
}
"}}
