import { statfs } from 'fs/promises';
import { db } from '../database';
import { redis } from '../cache';

const router = Router();

interface CheckResult {
  status: 'ok' | 'error';
  latencyMs?: number;
  error?: string;
}

async function checkDatabase(): Promise<CheckResult> {
  const start = Date.now();
  try {
    await db.query('SELECT 1');
    return { status: 'ok', latencyMs: Date.now() - start };
  } catch (err) {
    return { status: 'error', error: (err as Error).message };
  }
}

async function checkRedis(): Promise<CheckResult> {
  const start = Date.now();
  try {
    await redis.ping();
    return { status: 'ok', latencyMs: Date.now() - start };
  } catch (err) {
    return { status: 'error', error: (err as Error).message };
  }
}

async function checkDisk(): Promise<CheckResult> {
  try {
    const stats = await statfs('/');
    const freeGB = (stats.bfree * stats.bsize) / 1e9;
    const totalGB = (stats.blocks * stats.bsize) / 1e9;
    const usedPct = Math.round(((totalGB - freeGB) / totalGB) * 100);
    if (freeGB < 1) return { status: 'error', error: `Low disk: ${freeGB.toFixed(1)}GB free` };
    return { status: 'ok', latencyMs: usedPct }; // repurpose field as usage %
  } catch (err) {
    return { status: 'error', error: (err as Error).message };
  }
}

router.get('/health', async (req, res) => {
  const [database, cache, disk] = await Promise.all([
    checkDatabase(),
    checkRedis(),
    checkDisk(),
  ]);

  const allOk = [database, cache, disk].every(c => c.status === 'ok');

  res.status(allOk ? 200 : 503).json({
    status: allOk ? 'ok' : 'degraded',
    timestamp: new Date().toISOString(),
    checks: { database, cache, disk },
  });
});

router.get('/health/live', (req, res) => res.json({ status: 'ok' }));

export default router;
"}}
