import { Request, Response, NextFunction } from 'express';
import { db } from '../database';

export function authMiddleware(req: Request, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'No token' });
  const payload = jwt.verify(token, process.env.JWT_SECRET!, { algorithms: ['HS256'] }) as { userId: string };
  req.userId = payload.userId;
  next();
}

/** Require an org context — reads X-Org-Id header and verifies user is a member */
export async function requireOrg(req: Request, res: Response, next: NextFunction) {
  const orgId = req.headers['x-org-id'] as string;
  if (!orgId) return res.status(400).json({ error: 'X-Org-Id header required' });

  const { rows } = await db.query(
    'SELECT role FROM organization_members WHERE org_id = $1 AND user_id = $2',
    [orgId, req.userId]
  );
  if (rows.length === 0) return res.status(403).json({ error: 'Not a member of this organization' });

  req.orgId = orgId;
  req.orgRole = rows[0].role;
  next();
}
