import { CircuitBreaker, ConsecutiveBreaker, ExponentialBackoff, retry, handleAll } from 'cockatiel';
import { logger } from './logger';

const poolConfig: PoolConfig = {
  connectionString: process.env.DATABASE_URL,
  max: 20,                    // max connections in pool
  min: 2,                     // maintain at least 2 idle connections
  idleTimeoutMillis: 30_000,  // close idle connections after 30s
  connectionTimeoutMillis: 5_000, // fail fast if no connection available
  statement_timeout: 30_000,  // kill queries running > 30s
};

export const db = new Pool(poolConfig);

// Log pool events
db.on('error', (err) => logger.error({ err }, 'Database pool error'));
db.on('connect', () => logger.debug('New DB connection established'));

// Circuit breaker: open after 5 consecutive failures, retry after 30s
const breaker = new CircuitBreaker(handleAll, {
  halfOpenAfter: 30_000,
  breaker: new ConsecutiveBreaker(5),
});

breaker.onBreak(() => logger.error('Database circuit breaker OPEN — stopping queries'));
breaker.onReset(() => logger.info('Database circuit breaker CLOSED — resuming queries'));

// Retry policy: 3 attempts with exponential backoff
const retryPolicy = retry(handleAll, {
  maxAttempts: 3,
  backoff: new ExponentialBackoff({ initialDelay: 100, maxDelay: 2000 }),
});

export async function query(sql: string, params?: unknown[]) {
  return breaker.execute(() =>
    retryPolicy.execute(() => db.query(sql, params))
  );
}
"}}
