{"name": "write_file", "arguments": {"path": "src/env.ts", "content": "/**
 * Environment variable validation.
 * Supports both URL-format and Unix socket path format for DATABASE_URL.
 *  URL format:    postgres://user:pass@host:5432/dbname
 *  Socket format: /var/run/postgresql/.s.PGSQL.5432 (common in Linux distros)
 */

function isValidDatabaseUrl(value: string): boolean {
  // Unix socket path
  if (value.startsWith('/')) return true;

  // Standard URL
  try {
    const parsed = new URL(value);
    return ['postgres:', 'postgresql:'].includes(parsed.protocol);
  } catch {
    return false;
  }
}

export function validateEnv() {
  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) throw new Error('DATABASE_URL is required');
  if (!isValidDatabaseUrl(dbUrl)) {
    throw new Error(
      `DATABASE_URL is invalid. Expected postgres://... URL or /path/to/socket. Got: ${dbUrl.slice(0, 40)}`
    );
  }

  const jwtSecret = process.env.JWT_SECRET;
  if (!jwtSecret) throw new Error('JWT_SECRET is required');
  if (jwtSecret.length < 32) throw new Error('JWT_SECRET must be at least 32 characters');

  return { databaseUrl: dbUrl, jwtSecret };
}
