The migrations use plain numbered SQL files. I'll write a TypeScript CLI that tracks applied migrations in a `schema_migrations` table and applies new ones.

```tool_call
{"name": "write_file", "arguments": {"path": "scripts/migrate.ts", "content": "#!/usr/bin/env npx tsx
"""
Usage:
  npx tsx scripts/migrate.ts up       Apply all pending migrations
  npx tsx scripts/migrate.ts down     Roll back the last migration
  npx tsx scripts/migrate.ts status   Show applied and pending migrations
  npx tsx scripts/migrate.ts create <name>  Create a new migration file
"""

import { Pool } from 'pg';
import { readdirSync, readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

const db = new Pool({ connectionString: process.env.DATABASE_URL });
const MIGRATIONS_DIR = 'migrations';

async function ensureMigrationsTable() {
  await db.query(`
    CREATE TABLE IF NOT EXISTS schema_migrations (
      version VARCHAR(255) PRIMARY KEY,
      applied_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    )
  `);
}

async function getApplied(): Promise<Set<string>> {
  const { rows } = await db.query('SELECT version FROM schema_migrations ORDER BY version');
  return new Set(rows.map((r: { version: string }) => r.version));
}

function getMigrationFiles(): string[] {
  return readdirSync(MIGRATIONS_DIR)
    .filter(f => f.endsWith('.sql'))
    .sort();
}

async function runUp() {
  await ensureMigrationsTable();
  const applied = await getApplied();
  const files = getMigrationFiles();
  const pending = files.filter(f => !applied.has(f));

  if (pending.length === 0) {
    console.log('Nothing to migrate.');
    return;
  }

  for (const file of pending) {
    const sql = readFileSync(join(MIGRATIONS_DIR, file), 'utf-8');
    console.log(`Applying: ${file}`);
    await db.query('BEGIN');
    try {
      await db.query(sql);
      await db.query('INSERT INTO schema_migrations (version) VALUES ($1)', [file]);
      await db.query('COMMIT');
      console.log(`  OK: ${file}`);
    } catch (err) {
      await db.query('ROLLBACK');
      console.error(`  FAILED: ${file}:`, (err as Error).message);
      process.exit(1);
    }
  }
  console.log(`Applied ${pending.length} migration(s).`);
}

async function runStatus() {
  await ensureMigrationsTable();
  const applied = await getApplied();
  const files = getMigrationFiles();
  console.log('\nMigration Status:');
  for (const file of files) {
    const status = applied.has(file) ? '✓ applied' : '✗ pending';
    console.log(`  ${status}  ${file}`);
  }
  const pending = files.filter(f => !applied.has(f));
  console.log(`\n${applied.size} applied, ${pending.length} pending\n`);
}

function createMigration(name: string) {
  const seq = String(getMigrationFiles().length + 1).padStart(3, '0');
  const slug = name.toLowerCase().replace(/\s+/g, '_');
  const filename = `${seq}_${slug}.sql`;
  const path = join(MIGRATIONS_DIR, filename);
  writeFileSync(path, `-- Migration: ${name}\n-- Created: ${new Date().toISOString()}\n\n`);
  console.log(`Created: ${path}`);
}

async function main() {
  const [,, cmd, arg] = process.argv;
  try {
    if (cmd === 'up') await runUp();
    else if (cmd === 'status') await runStatus();
    else if (cmd === 'create' && arg) createMigration(arg);
    else { console.log('Usage: migrate.ts up | status | create <name>'); process.exit(1); }
  } finally {
    await db.end();
  }
}

main().catch((err) => { console.error(err); process.exit(1); });
"}}
