I'll build a lightweight feature flag system backed by environment variables for simple flags, with support for percentage rollouts and user-specific overrides.

```tool_call
{"name": "write_file", "arguments": {"path": "src/features.ts", "content": "/**
 * Feature flag system.
 * Flags are configured via environment variables:
 *   FF_NEW_DASHBOARD=true            — simple boolean flag
 *   FF_DARK_MODE=rollout:50          — 50% of users (consistent hash)
 *   FF_BETA_API=users:alice,bob      — specific users only
 */

import { createHash } from 'crypto';

type FlagConfig =
  | { type: 'boolean'; value: boolean }
  | { type: 'rollout'; percentage: number }
  | { type: 'users'; userIds: string[] };

function parseFlag(name: string): FlagConfig | null {
  const raw = process.env[`FF_${name.toUpperCase()}`];
  if (!raw) return null;

  if (raw === 'true') return { type: 'boolean', value: true };
  if (raw === 'false') return { type: 'boolean', value: false };
  if (raw.startsWith('rollout:')) {
    const pct = parseInt(raw.slice(8));
    return { type: 'rollout', percentage: isNaN(pct) ? 0 : pct };
  }
  if (raw.startsWith('users:')) {
    return { type: 'users', userIds: raw.slice(6).split(',').map(u => u.trim()) };
  }
  return null;
}

/**
 * Check if a feature is enabled for a given user.
 * @param flag - Flag name (e.g. 'new_dashboard')
 * @param userId - User ID for rollout/user-specific flags
 */
export function isEnabled(flag: string, userId?: string): boolean {
  const config = parseFlag(flag);
  if (!config) return false;

  switch (config.type) {
    case 'boolean':
      return config.value;

    case 'rollout': {
      if (!userId) return false;
      // Hash userId + flag name to get a stable 0-99 bucket
      const hash = createHash('md5').update(`${flag}:${userId}`).digest('hex');
      const bucket = parseInt(hash.slice(0, 8), 16) % 100;
      return bucket < config.percentage;
    }

    case 'users':
      return userId ? config.userIds.includes(userId) : false;
  }
}

/** Middleware that attaches flag checker to req */
export function featureFlagMiddleware(req: any, res: any, next: any) {
  req.isFeatureEnabled = (flag: string) => isEnabled(flag, req.userId);
  next();
}
"}}
