import { createInterface } from 'readline';
import { Pool } from 'pg';

const db = new Pool({ connectionString: process.env.DATABASE_URL });

interface EventRecord {
  timestamp: Date;
  eventType: string;
  userId: string;
}

function parseLogLine(line: string): EventRecord | null {
  const timestampMatch = line.match(/^(\S+)/);
  const eventTypeMatch = line.match(/event_type=(\S+)/);
  const userIdMatch = line.match(/user_id=(\S+)/);

  if (!timestampMatch || !eventTypeMatch || !userIdMatch) return null;

  return {
    timestamp: new Date(timestampMatch[1]),
    eventType: eventTypeMatch[1],
    userId: userIdMatch[1],
  };
}

function truncateToHour(date: Date): Date {
  const d = new Date(date);
  d.setMinutes(0, 0, 0);
  return d;
}

async function processLogFile(filePath: string) {
  console.log(`Processing: ${filePath}`);

  // Aggregate in memory: Map<hour:eventType, { count, users: Set }>
  const aggregated = new Map<string, { hour: Date; eventType: string; count: number; users: Set<string> }>();

  const rl = createInterface({ input: createReadStream(filePath), crlfDelay: Infinity });
  let lineCount = 0;
  let skipped = 0;

  for await (const line of rl) {
    if (!line.trim()) continue;
    const record = parseLogLine(line);
    if (!record) { skipped++; continue; }

    const hour = truncateToHour(record.timestamp);
    const key = `${hour.toISOString()}:${record.eventType}`;

    if (!aggregated.has(key)) {
      aggregated.set(key, { hour, eventType: record.eventType, count: 0, users: new Set() });
    }
    const entry = aggregated.get(key)!;
    entry.count++;
    entry.users.add(record.userId);
    lineCount++;
  }

  console.log(`Parsed ${lineCount} events (${skipped} skipped), ${aggregated.size} hour+type combinations`);

  // Write to database with upsert
  let inserted = 0;
  for (const { hour, eventType, count, users } of aggregated.values()) {
    await db.query(
      `INSERT INTO hourly_event_stats (hour, event_type, event_count, unique_users, processed_at)
       VALUES ($1, $2, $3, $4, NOW())
       ON CONFLICT (hour, event_type) DO UPDATE SET
         event_count = EXCLUDED.event_count,
         unique_users = EXCLUDED.unique_users,
         processed_at = NOW()`,
      [hour, eventType, count, users.size]
    );
    inserted++;
  }

  console.log(`Upserted ${inserted} rows into hourly_event_stats`);
}

async function main() {
  const files = process.argv.slice(2);
  if (files.length === 0) {
    console.error('Usage: npx tsx scripts/process-events.ts logs/events.log [...]');
    process.exit(1);
  }
  for (const file of files) {
    await processLogFile(file);
  }
  await db.end();
}

main().catch((err) => { console.error(err); process.exit(1); });
"}}
