import { AppError } from '../errors';
import { logger } from '../logger';

export function errorHandler(err: Error, req: Request, res: Response, next: NextFunction) {
  if (err instanceof AppError) {
    // Expected error — log as warning, return structured response
    logger.warn({ code: err.code, statusCode: err.statusCode, path: req.path }, err.message);
    return res.status(err.statusCode).json({
      error: {
        code: err.code,
        message: err.message,
        ...(err as any).fields ? { fields: (err as any).fields } : {},
      },
    });
  }

  // Unexpected error — log as error with full stack
  logger.error({ err, path: req.path, method: req.method }, 'Unhandled error');
  res.status(500).json({
    error: {
      code: 'INTERNAL_ERROR',
      message: process.env.NODE_ENV === 'production'
        ? 'An unexpected error occurred'
        : err.message, // show details in dev
    },
  });
}
