{"content": "import { db } from '../database';
import { processPayment } from './PaymentService';

export async function placeOrder(userId: string, items: Item[]) {
  // Check if user has enough credits
  const { rows } = await db.query('SELECT credits FROM users WHERE id = $1', [userId]);
  const userCredits = rows[0].credits;
  const total = items.reduce((sum, i) => sum + i.price, 0);

  if (userCredits < total) throw new Error('Insufficient credits');

  // Deduct credits and create order
  await db.query('UPDATE users SET credits = credits - $1 WHERE id = $2', [total, userId]);
  const { rows: orderRows } = await db.query(
    'INSERT INTO orders (user_id, total, status) VALUES ($1,$2,$3) RETURNING id',
    [userId, total, 'pending']
  );

  // Process payment
  await processPayment(userId, total);

  await db.query("UPDATE orders SET status='completed' WHERE id=$1", [orderRows[0].id]);
  return orderRows[0].id;
}
"}

Found the race condition. The check-then-act pattern on credits is not atomic:

1. User A requests order
2. User B requests order simultaneously  
3. Both threads read `credits = 100`, both see sufficient balance
4. Both deduct credits → user ends up with negative credits and two orders

Also: credits are deducted before payment processing. If payment fails after deduction, credits are lost. The fix is a database transaction with row-level locking (`SELECT ... FOR UPDATE`).

```tool_call
{"name": "write_file", "arguments": {"path": "src/services/OrderService.ts", "content": "import { db } from '../database';
import { processPayment } from './PaymentService';
import { InsufficientCreditsError } from '../errors';

export async function placeOrder(userId: string, items: Item[]) {
  const total = items.reduce((sum, i) => sum + i.price, 0);
  const client = await db.connect();

  try {
    await client.query('BEGIN');

    // FOR UPDATE locks this user row — concurrent placeOrder calls block here
    // until the transaction commits, preventing double-spend
    const { rows } = await client.query(
      'SELECT credits FROM users WHERE id = $1 FOR UPDATE',
      [userId]
    );
    const userCredits = rows[0]?.credits ?? 0;

    if (userCredits < total) {
      await client.query('ROLLBACK');
      throw new InsufficientCreditsError(userCredits, total);
    }

    // Create order first (before charging), marked pending
    const { rows: orderRows } = await client.query(
      'INSERT INTO orders (user_id, total, status) VALUES ($1,$2,$3) RETURNING id',
      [userId, total, 'pending']
    );
    const orderId = orderRows[0].id;

    // Process payment — if this fails, transaction rolls back (no deduction)
    await processPayment(userId, total);

    // Only deduct credits and complete after payment succeeds
    await client.query('UPDATE users SET credits = credits - $1 WHERE id = $2', [total, userId]);
    await client.query("UPDATE orders SET status='completed' WHERE id=$1", [orderId]);

    await client.query('COMMIT');
    return orderId;
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release();
  }
}
"}}
