import { db } from '../database';

/**
 * Idempotency middleware for POST/PUT routes.
 * Client sends: Idempotency-Key: <uuid>
 * If we've seen this key + userId before, return the cached response.
 * This prevents duplicate charges if clients retry failed requests.
 */
export async function idempotencyMiddleware(req: Request, res: Response, next: NextFunction) {
  const key = req.headers['idempotency-key'] as string;
  if (!key) return next(); // Optional — only active when header is sent

  // Check for existing response
  const { rows } = await db.query(
    `SELECT response_body, status_code FROM idempotency_keys
     WHERE key = $1 AND user_id = $2 AND created_at > NOW() - INTERVAL '24 hours'`,
    [key, req.userId]
  );

  if (rows[0]) {
    // Replay the original response
    res.setHeader('Idempotent-Replayed', 'true');
    return res.status(rows[0].status_code).json(rows[0].response_body);
  }

  // Intercept the response to store it
  const originalJson = res.json.bind(res);
  res.json = (body: unknown) => {
    // Store async, don't await (response is already sent)
    db.query(
      'INSERT INTO idempotency_keys (key, user_id, response_body, status_code) VALUES ($1,$2,$3,$4) ON CONFLICT (key) DO NOTHING',
      [key, req.userId, JSON.stringify(body), res.statusCode]
    ).catch(() => {}); // Best effort
    return originalJson(body);
  };

  next();
}
"}}
