{"name": "write_file", "arguments": {"path": "src/trace.ts", "content": "import { AsyncLocalStorage } from 'async_hooks';
import { v4 as uuidv4 } from 'uuid';
import { Request, Response, NextFunction } from 'express';

interface TraceContext {
  requestId: string;
  userId?: string;
}

// AsyncLocalStorage propagates context through async call chains automatically
const storage = new AsyncLocalStorage<TraceContext>();

export function getTraceContext(): TraceContext | undefined {
  return storage.getStore();
}

export function getRequestId(): string {
  return storage.getStore()?.requestId || 'no-trace';
}

/** Middleware: assigns a request ID to every incoming request */
export function tracingMiddleware(req: Request, res: Response, next: NextFunction) {
  // Accept incoming trace ID (from upstream service) or generate new one
  const requestId = (req.headers['x-request-id'] as string) || uuidv4();

  // Echo it back so clients can correlate client-side logs
  res.setHeader('X-Request-Id', requestId);

  const ctx: TraceContext = { requestId };

  // Run everything in this request's async context
  storage.run(ctx, () => next());
}

/** Call this after auth middleware to add userId to trace context */
export function setTraceUser(userId: string) {
  const ctx = storage.getStore();
  if (ctx) ctx.userId = userId;
}
"}}
