{"name": "write_file", "arguments": {"path": "src/logger.ts", "content": "import pino from 'pino';
import { getRequestId } from './trace';

const base = pino({ level: process.env.LOG_LEVEL || 'info' });

// Proxy that injects requestId into every log call automatically
export const logger = new Proxy(base, {
  get(target, prop) {
    if (['info', 'warn', 'error', 'debug', 'trace', 'fatal'].includes(prop as string)) {
      return (obj: unknown, msg?: string) => {
        const requestId = getRequestId();
        if (typeof obj === 'object' && obj !== null) {
          (target as any)[prop]({ requestId, ...obj as object }, msg);
        } else {
          (target as any)[prop]({ requestId }, obj as string);
        }
      };
    }
    return (target as any)[prop];
  },
});
"}}
